-- Check existing policies\nSELECT schemaname, tablename, policyname, permissive, roles, cmd, qual \nFROM pg_policies \nWHERE tablename = 'trial_requests';\n\n-- Make sure RLS allows authenticated users to insert\nALTER TABLE trial_requests ENABLE ROW LEVEL SECURITY;\n\n-- Drop and recreate policies cleanly\nDROP POLICY IF EXISTS "Users can insert their own trial requests" ON trial_requests;\nDROP POLICY IF EXISTS "Authenticated users can insert trial requests" ON trial_requests;\nDROP POLICY IF EXISTS "Anyone can insert trial requests" ON trial_requests;\nDROP POLICY IF EXISTS "trial_requests_insert_policy" ON trial_requests;\n\n-- Allow any authenticated user to insert (and also anon for edge cases)\nCREATE POLICY "trial_requests_insert_policy" ON trial_requests\n  FOR INSERT TO authenticated\n  WITH CHECK (true);\n\n-- Allow users to insert even if student_id doesn't match (for flexibility)\nCREATE POLICY "trial_requests_anon_insert" ON trial_requests\n  FOR INSERT TO anon\n  WITH CHECK (true);\n\n-- Allow authenticated users to read their own requests\nCREATE POLICY "trial_requests_select_own" ON trial_requests\n  FOR SELECT TO authenticated\n  USING (student_id = auth.uid() OR student_id IS NULL);